import{_ as o,o as i,c as e,ai as l}from"./chunks/framework.CaiDwmc7.js";const m=JSON.parse('{"title":"框架面试总览：Spring / SpringBoot / MyBatis 高频 8 题","description":"","frontmatter":{},"headers":[],"relativePath":"framework/overview.md","filePath":"framework/overview.md"}'),a={name:"framework/overview.md"};function t(n,r,s,c,p,g){return i(),e("div",null,[...r[0]||(r[0]=[l('<h1 id="框架面试总览-spring-springboot-mybatis-高频-8-题" tabindex="-1">框架面试总览：Spring / SpringBoot / MyBatis 高频 8 题 <a class="header-anchor" href="#框架面试总览-spring-springboot-mybatis-高频-8-题" aria-label="Permalink to “框架面试总览：Spring / SpringBoot / MyBatis 高频 8 题”">​</a></h1><blockquote><p>这篇不是从零教你 Spring，而是帮我梳理一遍<strong>初/中级面试最常问的框架题</strong>，细节放在后面的专题文章里慢慢看。</p></blockquote><hr><h2 id="一、框架高频面试题总表" tabindex="-1">一、框架高频面试题总表 <a class="header-anchor" href="#一、框架高频面试题总表" aria-label="Permalink to “一、框架高频面试题总表”">​</a></h2><ol><li><p><strong>能不能通俗地讲讲什么是 Spring IoC 和 DI？项目里带来了什么好处？</strong></p><ul><li>关键点：控制反转、依赖注入、解耦、通过注解 + 容器管理 Bean。</li><li>👉 详细见：<a href="/framework/spring-core.html">Spring 核心原理（IoC 与 AOP）</a></li></ul></li><li><p><strong>AOP 是什么？你们项目里在哪些场景用到了 AOP？</strong></p><ul><li>关键点：横切关注点、日志、权限校验、埋点、事务、本质是动态代理。</li><li>👉 详细见：<a href="/framework/spring-core.html">Spring 核心原理（IoC 与 AOP）</a></li></ul></li><li><p><strong><code>@Transactional</code> 是怎么实现事务的？什么时候会“事务失效”？</strong></p><ul><li>关键点：AOP 代理 + 动态代理、方法必须通过代理对象调用、<code>public</code> 方法、同类内部调用会失效等。</li><li>👉 详细见：<a href="/framework/transaction-propagation.html">事务传播机制详解</a>、<a href="/framework/transaction-scenario.html">场景实战：事务失效分析</a></li></ul></li><li><p><strong>能简单说一下 Spring Bean 的生命周期吗？</strong></p><ul><li>关键点：实例化 → 属性注入 → 初始化（各种回调）→ 销毁，<code>BeanPostProcessor</code>、<code>@PostConstruct</code> / <code>@PreDestroy</code>。</li><li>👉 详细见：<a href="/framework/bean-lifecycle.html">Bean 生命周期与循环依赖</a></li></ul></li><li><p><strong>什么是循环依赖？Spring 是怎么解决的？</strong>【中级】</p><ul><li>关键点：构造器循环依赖 vs setter 循环依赖、三级缓存思想。</li><li>👉 详细见：<a href="/framework/bean-lifecycle.html">Bean 生命周期与循环依赖</a></li></ul></li><li><p><strong>SpringBoot 相比传统 Spring 有什么优势？能说说自动配置的原理吗？</strong></p><ul><li>关键点：<code>starter</code>、约定大于配置、<code>@SpringBootApplication</code>、自动配置类、<code>spring.factories</code> / <code>AutoConfiguration</code>。</li><li>👉 详细见：<a href="/framework/springboot-principle.html">SpringBoot 原理</a></li></ul></li><li><p><strong>MyBatis 的一级缓存、二级缓存有什么区别？在项目里一般怎么用？</strong></p><ul><li>关键点：作用范围（SqlSession / Mapper 级别）、默认开启与否、和 Redis 缓存的关系。</li><li>👉 详细见：<a href="/framework/mybatis.html">MyBatis/MyBatis-Plus</a></li></ul></li><li><p><strong>常见的分层架构（Controller / Service / DAO）是怎么划分职责的？</strong></p><ul><li>关键点：Controller 负责接收请求和返回结果、Service 写业务逻辑、DAO/Mapper 只做数据访问。</li><li>可以准备一个自己项目里的简单接口，从 Controller 一路讲到 Mapper。</li></ul></li><li><p><strong>在 Spring 项目里，如何正确地使用多线程？高并发接口一般怎么做保护？</strong>【中级】</p><ul><li>关键点：统一使用 <code>ThreadPoolTaskExecutor</code> + <code>@Async</code> 管理线程；通过限流（拦截器 + Redis）、超时控制、幂等设计、防超卖等手段保护接口。</li><li>👉 详细见：<a href="/framework/concurrency-spring.html">Spring 中的多线程与高并发实战</a></li></ul></li></ol><p>建议：这 8 题先自己写一份<strong>“2～3 分钟的口述答案 + 可能被追问的点”</strong>，做到能顺着讲下来，不被打断。</p><hr><h2 id="二、如何使用这个框架面试模块" tabindex="-1">二、如何使用这个框架面试模块 <a class="header-anchor" href="#二、如何使用这个框架面试模块" aria-label="Permalink to “二、如何使用这个框架面试模块”">​</a></h2><ul><li><p><strong>第一步：先把这 8 题讲顺</strong><br> 面试前，可以自测一下：拿手机录音，从 IoC/AOP 讲到事务/自动配置，看自己能不能连贯说下来。</p></li><li><p><strong>第二步：对照专题文章补齐细节</strong><br> 哪一块感觉讲得空洞，就回到对应文档：</p><ul><li>IoC / AOP 基本概念与应用 → <code>/framework/spring-core</code></li><li>Bean 生命周期、循环依赖 → <code>/framework/bean-lifecycle</code></li><li>事务传播 &amp; 常见事务失效 → <code>/framework/transaction-propagation</code>、<code>/framework/transaction-scenario</code></li><li>SpringBoot 自动配置原理 → <code>/framework/springboot-principle</code></li><li>MyBatis 核心机制与常见坑 → <code>/framework/mybatis</code></li></ul></li><li><p><strong>第三步：准备 1～2 个和框架相关的项目案例</strong><br> 比如：</p><ul><li>“我们项目里有个下单接口，用了哪些注解、怎么通过 AOP 做日志/权限校验、用 <code>@Transactional</code> 保证下单过程的原子性……”</li><li>“曾经遇到过事务失效/循环依赖的问题，我是怎么排查并解决的……”</li><li>“系统有一些高并发接口（如下单、秒杀），我们是怎么用 <code>@Async + 线程池</code> 做异步处理、在网关/拦截器做限流、在业务层做幂等和防超卖的……”</li></ul></li></ul><p>面试里，只要围绕<strong>这 8 题 + 你自己的项目</strong>展开，大部分初/中级的框架相关问题都能比较从容地应对。</p>',10)])])}const f=o(a,[["render",t]]);export{m as __pageData,f as default};
